class Solution {
public:
    int calculate(string s) {
        int res = 0, num = 0, sign = 1;
        stack<int> st;
        for (char c : s) {
            if (isdigit(c)) num = num * 10 + (c - '0');
            else if (c == '+') {
                res += sign * num;
                num = 0;
                sign = 1;
            } else if (c == '-') {
                res += sign * num;
                num = 0;
                sign = -1;
            } else if (c == '(') st.push(res);
            else if (c == ')') {
                res = st.top(); st.pop();
                res += sign * num;
                num = 0;
                sign = 1;
            } else if (c == '*') sign *= num;
            else if (c == '/') sign /= num;
        }
        res += sign * num;
        return res;
    }
};
```
